"use strict";(globalThis.webpackChunkbitcoin_junioren=globalThis.webpackChunkbitcoin_junioren||[]).push([[763],{7763(a){a.exports=JSON.parse('{"ui":{"greeting":"Ahoy, {name}! \ud83c\udff4\u200d\u2620\ufe0f","title":"Bitcoin untuk Junior","subtitle":"Jelajahi dunia uang, nilai, dan Bitcoin!","progress":"Kemajuan","newPlayer":"Mulai pemain baru","newPlayerConfirm":"Mulai pemain baru? Kemajuan saat ini akan dihapus.","footer":"Berdasarkan Bitcoin untuk Junior oleh My First Bitcoin \xb7 CC BY-SA 4.0","nameScreen":{"title":"Ahoy, penjelajah!","subtitle":"Siapa namamu?","placeholder":"Namamu...","button":"Mulai petualangan! \ud83d\ude80"},"activity":{"back":"\u2190 Kembali","next":"Berikutnya \u2192","finish":"Selesai! \ud83c\udf89","correct":"Benar!","wrong":"Salah","score":"Skor","tryAgain":"Coba lagi","completed":"Selesai!","badgeEarned":"Lencana diperoleh!"},"sort":{"instruction":"Seret dari yang termurah ke yang termahal","check":"Periksa urutan"},"categorize":{"instruction":"Seret ke kategori yang tepat"},"match":{"instruction":"Pasangkan yang sesuai"},"truefalse":{"public":"Publik","private":"Pribadi"},"cipher":{"instruction":"Pecahkan kode dengan roda sandi"},"mining":{"instruction":"Temukan pasangan yang sama"},"scramble":{"instruction":"Susun kata yang berantakan","hint":"Petunjuk"},"moduleView":{"back":"\u2190 Kembali","map":"\u2190 Peta Harta","coreIdea":"\ud83d\udca1 Ide Utama","activities":"Aktivitas","module":"Modul"},"activityTypes":{"quiz":"Kuis","sort":"Mengurutkan","match":"Memasangkan","cipher":"Memecahkan Kode","mining":"Memori","truefalse":"Publik/Pribadi","categorize":"Mengategorikan","scramble":"Pemecah Kata"}},"modules":[{"id":1,"title":"Pertukaran, Nilai & Harga","icon":"\u2693","color":"#D97706","bg":"#FEF3C7","summary":"Nilai tergantung pada apa yang kamu butuhkan. Harga adalah berapa sesuatu itu biayanya. Uang memecahkan masalah pertukaran.","description":"Temukan mengapa kita menggunakan uang dan apa yang benar-benar bernilai!","badge":"\ud83c\udfdd\ufe0f Pedagang Pulau","activities":[{"type":"quiz","title":"Bertahan di Pulau","intro":"Kamu adalah korban kapal karam di pulau tak berpenghuni!","questions":[{"q":"Kamu terdampar di pulau terpencil. Apa yang paling berharga?","options":["\ud83d\udc8e Berlian","\ud83d\udd2a Parang","\ud83d\udcf1 Smartphone","\ud83d\udcb0 100 euro"],"correct":1,"explanation":"Di pulau terpencil, kamu bisa menggunakan parang untuk menebang kayu, memotong makanan, dan membangun tempat berlindung. Uang dan berlian tidak berguna di sana!"},{"q":"Kamu punya 5 kail tapi tidak punya tenda. Tetanggamu punya 3 tenda tapi tidak punya kail. Apa yang kalian lakukan?","options":["Keduanya menunggu","Tukar: satu kail untuk satu tenda!","Tidak ada yang dilakukan, sial","Menangis bersama"],"correct":1,"explanation":"Barter adalah cara tertua untuk berdagang! Kamu memberikan apa yang kamu lebih dari cukup untuk mendapatkan apa yang kamu butuhkan."},{"q":"Mengapa barter terkadang sangat sulit?","options":["Karena membosankan","Karena kamu harus menemukan seseorang yang menginginkan persis apa yang kamu miliki","Karena itu dilarang","Karena barang-barang terlalu berat"],"correct":1,"explanation":"Ini disebut \'kecocokan kebutuhan ganda\'. Uang memecahkan masalah ini \u2014 semua orang menerima uang!"},{"q":"Kerang dulunya digunakan sebagai uang. Apa yang membuat sesuatu menjadi uang yang baik?","options":["Harus indah","Harus langka, mudah dibawa, dan diterima semua orang","Harus bisa dimakan","Harus berasal dari pemerintah"],"correct":1,"explanation":"Uang yang baik itu langka (tidak tak terbatas), mudah dibawa, dan semua orang harus menerimanya sebagai alat pembayaran."},{"q":"Sebotol air harganya Rp10.000 di supermarket. Di gurun, seseorang menawarkanmu Rp1.000.000 untuk botol yang sama. Mengapa?","options":["Tokonya lebih mahal","Karena air di gurun jauh lebih langka dan penting","Airnya berbeda","Gurun itu jauh"],"correct":1,"explanation":"Kelangkaan mengubah nilai! Semakin sedikit sesuatu ada dan semakin kamu membutuhkannya, semakin berharga itu."},{"q":"Apa perbedaan antara harga dan nilai?","options":["Tidak ada perbedaan","Harga adalah berapa biaya sesuatu, nilai adalah seberapa penting sesuatu bagimu","Harga selalu lebih tinggi dari nilai","Nilai hanya tentang uang"],"correct":1,"explanation":"Gambar dari anakmu mungkin tidak ada harganya tapi sangat bernilai. Harga dan nilai itu tidak sama!"}]},{"type":"sort","title":"Garis Harga","intro":"Urutkan benda-benda dari yang termurah sampai yang termahal!","items":[{"name":"\ud83c\udf4e Apel","value":1},{"name":"\ud83d\udcd6 Buku","value":2},{"name":"\u26bd Bola Sepak","value":3},{"name":"\ud83d\udcf1 Ponsel","value":4},{"name":"\ud83d\udef5 Skuter","value":5},{"name":"\ud83c\udfe0 Rumah","value":6}]}]},{"id":2,"title":"Waktu, Energi & Hadiah","icon":"\u26a1","color":"#0D9488","bg":"#CCFBF1","summary":"Energi itu terbatas. Keseimbangan antara kerja, istirahat, dan bermain itu penting. Kesabaran menghasilkan hasil yang lebih baik.","description":"Bagaimana kamu menggunakan waktu dan energimu? Dan mengapa menunggu kadang lebih cerdas?","badge":"\u23f3 Penguasa Waktu","activities":[{"type":"categorize","title":"Kerja, Istirahat, atau Bermain?","intro":"Seret setiap aktivitas ke kategori yang tepat!","categories":["\ud83d\udcbc Kerja","\ud83d\ude34 Istirahat","\ud83c\udfae Bermain"],"items":[{"name":"Mengerjakan PR","cat":0},{"name":"Tidur","cat":1},{"name":"Bermain sepak bola","cat":2},{"name":"Membereskan kamar","cat":0},{"name":"Membaca buku","cat":1},{"name":"Bermain kejar-kejaran","cat":2},{"name":"Menyiapkan meja makan","cat":0},{"name":"Tidur siang","cat":1},{"name":"Main game","cat":2},{"name":"Belanja kebutuhan","cat":0},{"name":"Mendengarkan musik","cat":1},{"name":"Pergi ke taman bermain","cat":2}]},{"type":"quiz","title":"Pilihan Waktu","intro":"Apakah kamu memilih SEKARANG atau NANTI?","questions":[{"q":"Dalam cerita Tiga Babi Kecil: rumah mana yang tetap berdiri?","options":["\ud83c\udf3e Jerami (cepat dibangun)","\ud83e\udeb5 Kayu (sedang)","\ud83e\uddf1 Batu bata (butuh waktu paling lama)"],"correct":2,"explanation":"Rumah batu bata membutuhkan waktu dan usaha paling banyak, tetapi itulah satu-satunya yang tetap berdiri. Kesabaran itu terbayar!"},{"q":"Apa arti \'preferensi waktu rendah\'?","options":["Kamu ingin segalanya SEKARANG","Kamu bersedia menunggu untuk sesuatu yang lebih baik","Kamu tidak punya jam","Kamu banyak tidur"],"correct":1,"explanation":"Preferensi waktu rendah = bersedia menunggu untuk hasil yang lebih baik. Seperti babi yang membangun rumah batu!"},{"q":"Kamu mendapat 1 permen sekarang, atau 3 permen jika kamu menunggu 10 menit. Apa pilihan yang paling cerdas?","options":["1 permen SEKARANG!","Menunggu: 3 permen > 1 permen","Permen tidak sehat","Kabur"],"correct":1,"explanation":"Ini adalah tes marshmallow yang terkenal! Anak-anak yang bisa menunggu sering kali memiliki hasil yang lebih baik di sekolah."},{"q":"Kamu punya ujian penting besok. Apa itu preferensi waktu rendah?","options":["Main game sekarang dan belajar besok","Belajar hari ini supaya besok nilaimu bagus","Bolos ujian","Berharap pada keberuntungan"],"correct":1,"explanation":"Melakukan sesuatu yang sulit sekarang (belajar) agar mendapat sesuatu yang baik nanti (nilai bagus) \u2014 itulah preferensi waktu rendah."},{"q":"Apa yang terjadi jika kamu menghabiskan semua energimu di pagi hari?","options":["Kamu jadi lebih kuat","Kamu tidak punya sisa energi untuk sisa hari","Kamu mendapat kekuatan super","Tidak ada yang istimewa"],"correct":1,"explanation":"Energi itu terbatas! Membaginya dengan bijak itu penting \u2014 sama seperti uang."}]}]},{"id":3,"title":"Analog versus Digital","icon":"\ud83d\udd04","color":"#7C3AED","bg":"#EDE9FE","summary":"Teknologi terus berubah. Setiap penemuan memecahkan suatu masalah. Tidak semua yang baru otomatis lebih baik.","description":"Dari merpati pos hingga internet \u2014 bagaimana teknologi mengubah dunia!","badge":"\ud83d\ude80 Pionir Teknologi","activities":[{"type":"match","title":"Lama \u2194 Baru","intro":"Pasangkan setiap teknologi lama dengan versi modernnya!","pairs":[{"old":"\u2709\ufe0f Surat","new":"\ud83d\udce7 Email"},{"old":"\ud83d\udcde Telepon putar","new":"\ud83d\udcf1 Smartphone"},{"old":"\ud83d\uddfa\ufe0f Peta kertas","new":"\ud83d\udccd GPS"},{"old":"\ud83d\udcf7 Roll film","new":"\ud83d\udcf8 Kamera digital"},{"old":"\ud83d\udcf0 Koran","new":"\ud83c\udf10 Situs berita"},{"old":"\ud83d\udcb0 Uang koin","new":"\u20bf Bitcoin"}]},{"type":"quiz","title":"Bayangkan Masa Depan","intro":"Seperti apa teknologi dalam 20 tahun ke depan?","questions":[{"q":"Mengapa teknologi berubah dari waktu ke waktu?","options":["Karena barang lama rusak","Karena manusia memecahkan masalah dengan penemuan baru","Karena pemerintah menginginkannya","Tanpa alasan"],"correct":1,"explanation":"Setiap penemuan memecahkan masalah. Mobil memecahkan masalah bahwa kuda itu lambat dan bisa kelelahan!"},{"q":"Apakah teknologi baru SELALU lebih baik dari yang lama?","options":["Ya, selalu","Tidak, kadang yang lama lebih baik atau lebih andal","Teknologi baru tidak ada","Hanya jika lebih mahal"],"correct":1,"explanation":"Buku kertas tidak butuh baterai! Kadang solusi lama masih tetap cerdas."},{"q":"Bitcoin adalah uang digital. Apa kesamaannya dengan kerang zaman dulu?","options":["Keduanya berasal dari laut","Keduanya langka dan digunakan sebagai alat tukar","Tidak ada","Keduanya gratis"],"correct":1,"explanation":"Baik kerang maupun Bitcoin sama-sama langka (jumlahnya terbatas) dan digunakan sebagai alat tukar."},{"q":"Apa itu inovasi?","options":["Membeli sesuatu yang baru","Peningkatan atau penemuan cerdas yang memecahkan masalah","Kata sulit yang tidak berarti apa-apa","Hanya untuk ilmuwan"],"correct":1,"explanation":"Inovasi = solusi baru atau lebih baik untuk masalah yang sudah ada. Semua orang bisa berinovasi!"}]}]},{"id":4,"title":"Keamanan & Privasi","icon":"\ud83d\udee1\ufe0f","color":"#DC2626","bg":"#FEE2E2","summary":"Kamu menentukan informasi apa yang kamu bagikan. Kode melindungi pesan. Kepercayaan tidak selalu diperlukan jika kamu punya enkripsi.","description":"Kode rahasia, privasi, dan cara melindungi dirimu secara online!","badge":"\ud83d\udd10 Cypherpunk","activities":[{"type":"truefalse","title":"Publik atau Pribadi?","intro":"Apakah informasi ini publik atau pribadi? Putuskan dengan cepat!","statements":[{"text":"Kata sandimu","answer":false,"label":"Pribadi!","explanation":"Kata sandi selalu bersifat pribadi. Jangan pernah membagikannya!"},{"text":"Namamu di sekolah","answer":true,"label":"Publik","explanation":"Di sekolah, semua orang tahu namamu \u2014 itu adalah informasi publik."},{"text":"PIN-mu","answer":false,"label":"Pribadi!","explanation":"PIN-mu adalah rahasia \u2014 itu melindungi rekening bankmu."},{"text":"Taman di kota","answer":true,"label":"Publik","explanation":"Taman adalah tempat umum \u2014 semua orang boleh datang ke sana."},{"text":"Buku harianmu","answer":false,"label":"Pribadi!","explanation":"Buku harianmu bersifat pribadi \u2014 hanya kamu yang menentukan siapa yang boleh membacanya."},{"text":"Warna sepedamu","answer":true,"label":"Publik","explanation":"Semua orang bisa melihat warna sepedamu."},{"text":"Alamat rumahmu","answer":false,"label":"Pribadi!","explanation":"Alamatmu tidak dibagikan kepada orang asing \u2014 itu adalah informasi pribadi."},{"text":"Cuaca hari ini","answer":true,"label":"Publik","explanation":"Cuaca sama untuk semua orang \u2014 sepenuhnya publik!"},{"text":"Kunci Bitcoin-mu","answer":false,"label":"Pribadi!","explanation":"Kunci privatmu adalah rahasia terpenting. Siapa yang memilikinya, memiliki bitcoin-mu!"}]},{"type":"cipher","title":"Kode Rahasia","intro":"Pecahkan kata-kata rahasia Bitcoin dengan roda sandi!"}]},{"id":5,"title":"Urusan Keuangan","icon":"\ud83c\udfe6","color":"#B45309","bg":"#FEF3C7","summary":"Uang bisa kamu hasilkan, tabung, investasikan, dan belanjakan. Membuat anggaran adalah memilih. Aturan yang adil itu penting.","description":"Menghasilkan, menabung, berinvestasi \u2014 jadilah ahli keuangan!","badge":"\ud83d\udc8e Bijak Keuangan","activities":[{"type":"quiz","title":"Pintar dengan Uang","intro":"Uji seberapa pintar kamu dalam urusan keuangan!","questions":[{"q":"Apa itu menabung?","options":["Langsung menghabiskan uang","Menyisihkan uang untuk nanti","Membuang uang","Meminjam uang dari teman"],"correct":1,"explanation":"Menabung = menyimpan uang agar nanti bisa membeli sesuatu yang lebih besar atau lebih penting."},{"q":"Apa itu investasi?","options":["Menyembunyikan uang","Menempatkan uang atau waktumu pada sesuatu agar nilainya bertambah nanti","Menghabiskan semuanya hari ini","Membakar uang"],"correct":1,"explanation":"Investasi adalah menempatkan uang atau waktumu pada sesuatu dengan harapan nilainya akan lebih besar nanti."},{"q":"Kamu punya 12 kerang. Tenda harganya 8 dan kail harganya 6. Bisakah kamu membeli keduanya?","options":["Bisa!","Tidak bisa, 8 + 6 = 14, dan kamu hanya punya 12","Hanya dengan diskon","Kerang bukan uang"],"correct":1,"explanation":"8 + 6 = 14, tapi kamu hanya punya 12 kerang. Kamu harus memilih! Itulah yang disebut membuat anggaran."},{"q":"Dalam lelang, harga barang langka terus naik. Mengapa?","options":["Penjualnya jahat","Banyak orang menginginkannya, tapi hanya ada satu (kelangkaan + permintaan)","Barangnya semakin besar","Karena seseorang curang"],"correct":1,"explanation":"Ketika banyak orang menginginkan sesuatu tapi jumlahnya sedikit, harga naik. Itulah cara kerja penawaran dan permintaan!"},{"q":"Mengapa aturan yang adil dalam keuangan itu penting?","options":["Tidak penting","Agar semua orang mendapat kesempatan yang sama","Hanya untuk anak-anak","Agar semuanya lebih sulit"],"correct":1,"explanation":"Aturan yang adil memastikan tidak ada yang bisa curang dan semua orang mendapat kesempatan yang sama."},{"q":"Apa itu meminjam?","options":["Mencuri uang","Mendapatkan uang dari orang lain yang harus dikembalikan nanti","Menabung uang","Kehilangan uang"],"correct":1,"explanation":"Meminjam berarti kamu mendapatkan uang dari orang lain, tetapi harus mengembalikannya nanti \u2014 biasanya dengan tambahan (bunga)."}]}]},{"id":6,"title":"Dasar-Dasar Bitcoin","icon":"\u20bf","color":"#EA580C","bg":"#FFF7ED","summary":"Bitcoin adalah uang digital yang langka tanpa perantara. Mining mengonfirmasi transaksi. Satoshi tetap anonim.","description":"Petualangan Bitcoin yang besar: dari Satoshi hingga mining!","badge":"\u26cf\ufe0f Penambang Bitcoin","activities":[{"type":"quiz","title":"Siapa Satoshi?","intro":"Temukan kisah di balik Bitcoin!","questions":[{"q":"Siapa yang menciptakan Bitcoin?","options":["Elon Musk","Satoshi Nakamoto","Bank","Google"],"correct":1,"explanation":"Satoshi Nakamoto menerbitkan \'white paper\' pada tahun 2008 dengan ide untuk Bitcoin. Tidak ada yang tahu siapa Satoshi sebenarnya!"},{"q":"Apa itu \'white paper\'?","options":["Selembar kertas kosong","Dokumen yang menjelaskan ide baru","Surat rahasia","Tugas sekolah"],"correct":1,"explanation":"White paper adalah dokumen yang mempresentasikan ide atau solusi baru kepada dunia."},{"q":"Apa itu Genesis Block?","options":["Sebuah video game","Blok pertama dari Bitcoin","Sejenis batu","Kata sandi rahasia"],"correct":1,"explanation":"Pada 3 Januari 2009, Genesis Block dibuat \u2014 blok pertama dalam blockchain Bitcoin."},{"q":"Berapa banyak bitcoin yang akan pernah ada?","options":["Tak terbatas","Maksimal 21 juta","Tepat 1 miliar","Tidak ada yang tahu"],"correct":1,"explanation":"Tidak akan pernah ada lebih dari 21 juta bitcoin. Kelangkaan itu sudah tertanam dalam aturannya!"},{"q":"Apa itu \'mining\' dalam Bitcoin?","options":["Menggali di tanah","Menggunakan komputer untuk memecahkan teka-teki guna mengonfirmasi transaksi","Mencetak bitcoin","Menggambar bitcoin"],"correct":1,"explanation":"Para miner menggunakan komputer untuk memecahkan teka-teki matematika. Sebagai bukti bahwa mereka telah bekerja, mereka boleh mengonfirmasi transaksi."},{"q":"Apa itu Proof of Work?","options":["Laporan dari sekolah","Bukti bahwa seseorang benar-benar berusaha keras untuk mendapatkan sesuatu","Sebuah kata sandi","Sejenis ijazah"],"correct":1,"explanation":"Proof of Work = bukti kerja. Seperti permainan dadu: semua orang mengikuti aturan yang sama dan memiliki kesempatan yang sama."},{"q":"Mengapa Satoshi menghilang?","options":["Dia pergi berlibur","Kemungkinan agar Bitcoin benar-benar milik semua orang, tanpa pemimpin","Dia marah","Dia tidak ada"],"correct":1,"explanation":"Dengan menghilang, Satoshi memastikan Bitcoin bukan milik satu orang. Jaringan berjalan berdasarkan aturan, bukan pemimpin."}]},{"type":"mining","title":"Menambang Bitcoin!","intro":"Temukan pasangan yang sama untuk menambang blok \u2014 seperti penambang sungguhan!"},{"type":"scramble","title":"Pemecah Kata Bitcoin","intro":"Susun kata-kata Bitcoin yang berantakan!","words":[{"scrambled":"COINBIT","answer":"BITCOIN","hint":"Uang digital"},{"scrambled":"SHATISO","answer":"SATOSHI","hint":"Penemu misterius"},{"scrambled":"KOLB","answer":"BLOK","hint":"Transaksi tersimpan di sini"},{"scrambled":"ALANSGK","answer":"LANGKAS","hint":"Jumlahnya tidak banyak"},{"scrambled":"NAMBANG","answer":"TAMBANG","hint":"Memecahkan teka-teki dengan komputer"},{"scrambled":"FADLET","answer":"DAFLET","hint":"Tempat menyimpan bitcoin"}]}]}]}')}}]);